import{_ as a,o as c,c as o,a3 as r}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Namespace clore::generate::cache","description":"clore::generate::cache 命名空间负责实现生成过程的缓存子系统，通过文件系统持久化存储提示（prompt）与响应（response）的映射，以避免重复计算。其核心数据结构包括 CacheIndex（缓存索引）和 CacheError（错误类型），并围绕它们提供同步与异步操作：load_cache_index / load_cache_index_async 用于从指定路径加载索引，find_cached_response 在索引中查找缓存条目，save_cache_entry / save_cache_entry_async 将新条目持久化。此外，make_prompt_response_cache_key 生成唯一的缓存键，而 normalize_text_for_hashing 对文本进行规范化以保证键的一致性。这些功能共同构成了一个可复用的缓存层，降低了 clore::generate 中模型调用的开销。","frontmatter":{"title":"Namespace clore::generate::cache","description":"clore::generate::cache 命名空间负责实现生成过程的缓存子系统，通过文件系统持久化存储提示（prompt）与响应（response）的映射，以避免重复计算。其核心数据结构包括 CacheIndex（缓存索引）和 CacheError（错误类型），并围绕它们提供同步与异步操作：load_cache_index / load_cache_index_async 用于从指定路径加载索引，find_cached_response 在索引中查找缓存条目，save_cache_entry / save_cache_entry_async 将新条目持久化。此外，make_prompt_response_cache_key 生成唯一的缓存键，而 normalize_text_for_hashing 对文本进行规范化以保证键的一致性。这些功能共同构成了一个可复用的缓存层，降低了 clore::generate 中模型调用的开销。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/generate/cache/index.md","filePath":"zh/clore/namespaces/clore/generate/cache/index.md"}'),t={name:"zh/clore/namespaces/clore/generate/cache/index.md"};function n(d,e,h,s,i,l){return c(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="namespace-clore-generate-cache" tabindex="-1">Namespace <code>clore::generate::cache</code> <a class="header-anchor" href="#namespace-clore-generate-cache" aria-label="Permalink to &quot;Namespace `clore::generate::cache`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::generate::cache</code> 命名空间负责实现生成过程的缓存子系统，通过文件系统持久化存储提示（prompt）与响应（response）的映射，以避免重复计算。其核心数据结构包括 <code>CacheIndex</code>（缓存索引）和 <code>CacheError</code>（错误类型），并围绕它们提供同步与异步操作：<code>load_cache_index</code> / <code>load_cache_index_async</code> 用于从指定路径加载索引，<code>find_cached_response</code> 在索引中查找缓存条目，<code>save_cache_entry</code> / <code>save_cache_entry_async</code> 将新条目持久化。此外，<code>make_prompt_response_cache_key</code> 生成唯一的缓存键，而 <code>normalize_text_for_hashing</code> 对文本进行规范化以保证键的一致性。这些功能共同构成了一个可复用的缓存层，降低了 <code>clore::generate</code> 中模型调用的开销。</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-generate-cache-cacheerror" tabindex="-1"><code>clore::generate::cache::CacheError</code> <a class="header-anchor" href="#clore-generate-cache-cacheerror" aria-label="Permalink to &quot;`clore::generate::cache::CacheError`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:16</code></p><p>Definition: <code>generate/cache.cppm:16</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h3 id="clore-generate-cache-cacheindex" tabindex="-1"><code>clore::generate::cache::CacheIndex</code> <a class="header-anchor" href="#clore-generate-cache-cacheindex" aria-label="Permalink to &quot;`clore::generate::cache::CacheIndex`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:20</code></p><p>Definition: <code>generate/cache.cppm:20</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>entries</code> map contains string keys mapped to string values.</li><li>Keys are expected to be unique within the map.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>entries</code>: the underlying <code>std::unordered_map&lt;std::string, std::string&gt;</code> that holds the cache index data.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to look up cached results by key.</li><li>Populated and queried by cache management functions.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-generate-cache-find-cached-response" tabindex="-1"><code>clore::generate::cache::find_cached_response</code> <a class="header-anchor" href="#clore-generate-cache-find-cached-response" aria-label="Permalink to &quot;`clore::generate::cache::find_cached_response`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:35</code></p><p>Definition: <code>generate/cache.cppm:347</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>函数 <code>clore::generate::cache::find_cached_response</code> 在给定的 <code>CacheIndex</code> 中查找与指定键关联的缓存响应。第一个参数是 <code>const CacheIndex &amp;</code>，即缓存索引的引用；第二个参数是 <code>std::string_view</code>，表示要查找的键。如果找到对应的缓存条目，返回包含响应内容的 <code>std::optional&lt;std::string_view&gt;</code>；如果未找到，返回 <code>std::nullopt</code>。调用者必须确保传入的 <code>CacheIndex</code> 已通过 <code>load_cache_index</code> 或 <code>load_cache_index_async</code> 正确加载，且键已按照约定的格式（例如通过 <code>make_prompt_response_cache_key</code> 生成）提供。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to retrieve a previously cached generation response</li><li>used in conjunction with <code>save_cache_entry</code> or similar caching functions</li></ul><h3 id="clore-generate-cache-load-cache-index" tabindex="-1"><code>clore::generate::cache::load_cache_index</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:29</code></p><p>Definition: <code>generate/cache.cppm:252</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>函数 <code>clore::generate::cache::load_cache_index</code> 负责从指定位置加载缓存索引。调用者传入一个 <code>std::string_view</code> 参数，该参数标识缓存索引的存储位置（例如文件路径）。函数返回 <code>std::expected&lt;CacheIndex, CacheError&gt;</code>：成功时得到一个 <code>CacheIndex</code> 对象，可用于后续的缓存查询（如 <code>clore::generate::cache::find_cached_response</code>）或更新（如 <code>clore::generate::cache::save_cache_entry</code>）；失败时则返回一个 <code>CacheError</code> 描述错误原因。调用者应确保提供的标识符有效，并处理可能的错误情形。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Loading cache index for lookup</li><li>Called before <code>find_cached_response</code></li></ul><h3 id="clore-generate-cache-load-cache-index-async" tabindex="-1"><code>clore::generate::cache::load_cache_index_async</code> <a class="header-anchor" href="#clore-generate-cache-load-cache-index-async" aria-label="Permalink to &quot;`clore::generate::cache::load_cache_index_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:38</code></p><p>Definition: <code>generate/cache.cppm:356</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>该函数启动异步加载缓存索引的操作。调用者需提供一个文件路径（<code>std::string</code>）和一个 <code>kota::event_loop &amp;</code>，该事件循环用于调度异步工作。返回值是一个 <code>int</code>，表示操作的结果状态或句柄，具体含义需结合调用上下文解读。</p><p>与同步版本 <code>load_cache_index</code> 不同，此函数不阻塞调用线程，而是将加载任务交给事件循环处理。调用者应确保在操作完成前保持 <code>kota::event_loop</code> 处于活跃状态。返回的整数可用于后续检查操作是否已成功完成，或与异步 I/O 机制对接。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to obtain the cache index asynchronously before cache lookups or modifications</li><li>Used in coroutine contexts that need to interact with the generation cache</li></ul><h3 id="clore-generate-cache-make-prompt-response-cache-key" tabindex="-1"><code>clore::generate::cache::make_prompt_response_cache_key</code> <a class="header-anchor" href="#clore-generate-cache-make-prompt-response-cache-key" aria-label="Permalink to &quot;`clore::generate::cache::make_prompt_response_cache_key`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:24</code></p><p>Definition: <code>generate/cache.cppm:219</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>根据提供的提示文本、响应文本和整数参数，生成一个可用于缓存查找或存储的唯一且确定的缓存键。该函数返回 <code>std::expected&lt;std::string, CacheError&gt;</code>，在成功时返回缓存键字符串，失败时返回 <code>CacheError</code> 以指示键生成过程中的错误。生成的键旨在与 <code>clore::generate::cache</code> 模块中的其他缓存操作（如 <code>find_cached_response</code> 或 <code>save_cache_entry</code>）配合使用。</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to generate a unique cache key for storing or retrieving cached responses</li><li>called by cache lookup and insertion functions</li></ul><h3 id="clore-generate-cache-normalize-text-for-hashing" tabindex="-1"><code>clore::generate::cache::normalize_text_for_hashing</code> <a class="header-anchor" href="#clore-generate-cache-normalize-text-for-hashing" aria-label="Permalink to &quot;`clore::generate::cache::normalize_text_for_hashing`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:192</code></p><p>Definition: <code>generate/cache.cppm:192</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>Declaration: <a href="./functions/normalize-text-for-hashing">Declaration</a></p><p>该函数接受一个 <code>std::string_view</code> 并返回一个 <code>std::string</code>，用于将输入文本规范化为可预测、可重复的格式，以便后续用于哈希运算。调用者可以期望：对于内容相同但细微差异（如空白字符、大小写或标点）的两个输入，函数能生成相同的规范化输出，从而确保哈希键的一致性。此函数是 <code>make_prompt_response_cache_key</code> 内部流程的一部分，用于生成缓存键的组件。</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called by <code>clore::generate::cache::make_prompt_response_cache_key</code> to normalize prompt or response text before hashing</li><li>used to ensure consistent cache keys regardless of whitespace variation</li></ul><h3 id="clore-generate-cache-save-cache-entry" tabindex="-1"><code>clore::generate::cache::save_cache_entry</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:31</code></p><p>Definition: <code>generate/cache.cppm:303</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p>调用者应当通过提供三个字符串视图参数来请求持久化一条缓存记录：第一个参数标识缓存键，第二个参数是要缓存的数据内容，第三个参数携带额外的上下文信息（例如对应的原始请求或规范化后的文本）。函数会同步执行写入操作并返回 <code>std::expected&lt;void, CacheError&gt;</code>：若成功则返回无值的预期，否则返回描述写入失败的 <code>CacheError</code>。调用者需要检查该返回值以确认操作是否成功，并据此决定后续流程。</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called after a successful generation to persist the response</li><li>synchronous version of <code>save_cache_entry_async</code></li><li>invoked by higher-level generation routines</li></ul><h3 id="clore-generate-cache-save-cache-entry-async" tabindex="-1"><code>clore::generate::cache::save_cache_entry_async</code> <a class="header-anchor" href="#clore-generate-cache-save-cache-entry-async" aria-label="Permalink to &quot;`clore::generate::cache::save_cache_entry_async`&quot;">​</a></h3><p>Declaration: <code>generate/cache.cppm:41</code></p><p>Definition: <code>generate/cache.cppm:376</code></p><p>Implementation: <a href="./../../../../modules/generate/cache"><code>Module generate:cache</code></a></p><p><code>clore::generate::cache::save_cache_entry_async</code> 接受三个 <code>std::string</code> 参数（分别代表缓存键、提示和响应内容）以及一个 <code>kota::event_loop &amp;</code>，用于异步保存缓存条目。该函数启动一个异步操作，将提供的键值对写入缓存，并在事件循环上调度完成处理；返回一个 <code>int</code>，可能表示操作标识符或状态码。调用者应确保事件循环保持活动，直到操作完成，并通过异步回调或后续处理获取最终结果。</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to persist a generated response asynchronously</li><li>Used after response generation to avoid blocking the main thread</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::generate</a></li></ul>',74)])])}const _=a(t,[["render",n]]);export{g as __pageData,_ as default};
